191	        internal SortDirection GetColumnSortDirection(string? columnName)
192	        {
193	            if (columnName == null)
194	            {
195	                return SortDirection.None;
196	            }
197	
198	            if (SortDefinitions.TryGetValue(columnName, out var sortDefinition))
199	            {
200	                return sortDefinition.Descending ? SortDirection.Descending : SortDirection.Ascending;
201	            }
202	
203	            return SortDirection.None;
204	        }
