206	        protected int numPages
207	        {
208	            get
209	            {
210	                if (HasServerData)
211	                    return (int)Math.Ceiling(_serverData.TotalItems / (double)RowsPerPage);
212	
213	                return (int)Math.Ceiling(FilteredItems.Count() / (double)RowsPerPage);
214	            }
215	        }
