2497	            groupedColumns = [.. groupedColumns.Where(x => x.GroupingState.Value).OrderBy(x => x._groupByOrderState.Value)];
2498	            // it's only groupable if a column can be grouped
2499	            isGroupable = isGroupable && groupedColumns.Count > 0;
2500	
2501	            if (!isGroupable || GetFilteredItemsCount() == 0)
2502	            {
2503	                if (_isFirstRendered && !noStateChange)
2504	                    StateHasChanged();
2505	                return;
2506	            }
2507	
2508	            // Initialize with the first group definition
2509	            _groupDefinition = ProcessGroup(groupedColumns[0]);
2510	
2511	            // Create a reference to build the hierarchy
2512	            var currentGroupDef = _groupDefinition;
2513	
2514	            // Start from index 1 since we've already processed the first column
2515	            for (var i = 1; i < groupedColumns.Count; i++)
2516	            {
2517	                var nextGroupDef = ProcessGroup(groupedColumns[i]);
2518	                // Connect it to the current level
2519	                currentGroupDef.InnerGroup = nextGroupDef;
2520	                // Move to the next level for the next iteration
2521	                currentGroupDef = nextGroupDef;
2522	            }
2523	
2524	            if ((_isFirstRendered || HasServerData) && !noStateChange)
2525	                StateHasChanged();
2526	        }
