2536	        internal IEnumerable<IGrouping<object?, T>> GetItemsOfGroup(GroupDefinition<T>? parent, IEnumerable<T>? sourceList)
2537	        {
2538	            if (parent is null || sourceList is null)
2539	            {
2540	                return new List<IGrouping<object, T>>();
2541	            }
2542	
2543	            if (parent.Selector is not null)
2544	            {
2545	                return sourceList.GroupBy(parent.Selector).ToList();
2546	            }
2547	
2548	            return new List<IGrouping<object, T>>();
2549	        }
