2551	        private GroupDefinition<T> ProcessGroup(Column<T> column)
2552	        {
2553	            var expanded = _groupInitialExpanded ?
2554	                            (GroupExpanded || column._groupExpandedState.Value) :
2555	                            column._groupExpandedState.Value;
2556	            return new()
2557	            {
2558	                DataGrid = this,
2559	                Selector = column.groupBy,
2560	                Expanded = expanded,
2561	                GroupTemplate = column.GetGroupTemplate(),
2562	                Indentation = column.GroupIndented,
2563	                Title = column.Title,
2564	                Grouping = new EmptyGrouping<object?, T>(null), // Ensure Grouping is not null
2565	                KeyPath = new GroupKeyPath([])
2566	            };
2567	        }
2568	
2569	        internal IEnumerable<GroupDefinition<T>> GetGroupDefinitions(GroupDefinition<T> groupDef, IEnumerable<IGrouping<object?, T>> groups)
2570	        {
2571	            List<GroupDefinition<T>> result = new();
2572	            foreach (var group in groups)
2573	            {
2574	                var expanded = false;
2575	                var currentKeyPath = groupDef.Parent?.KeyPath.ToList() ?? [];
2576	                GroupKeyPath? keyPath = null;
2577	                if (group is not null)
2578	                {
2579	                    currentKeyPath.Add(group.Key);
2580	                    keyPath = new GroupKeyPath(currentKeyPath);
2581	                    var key = new GroupKey(groupDef.Title, keyPath);
2582	                    expanded = _groupExpansionsDict.TryGetValue(key, out var value) ? value :
2583	                                   groupDef.Expanded;
2584	                    _groupExpansionsDict.TryAdd(key, expanded);
2585	                }
2586	                var newGroupDefinition = new GroupDefinition<T>
2587	                {
2588	                    DataGrid = this,
2589	                    Selector = groupDef.Selector,
2590	                    Expanded = expanded,
2591	                    GroupTemplate = groupDef.GroupTemplate,
2592	                    Indentation = groupDef.Indentation,
2593	                    Title = groupDef.Title,
2594	                    Parent = groupDef.Parent,
2595	                    Grouping = group ?? new EmptyGrouping<object?, T>(null),
2596	                    KeyPath = keyPath ?? new GroupKeyPath(currentKeyPath),
2597	                };
2598	
2599	                var innerGroup = groupDef.InnerGroup;
2600	                if (innerGroup != null)
2601	                {
2602	                    // Create a new InnerGroup instance to prevent unwanted side effects from shared references at different grouping levels (e.g., tracking the Expanded state)
2603	                    newGroupDefinition.InnerGroup = new GroupDefinition<T>
2604	                    {
2605	                        DataGrid = this,
2606	                        Selector = innerGroup.Selector,
2607	                        Expanded = innerGroup.Expanded,
2608	                        GroupTemplate = innerGroup.GroupTemplate,
2609	                        Indentation = innerGroup.Indentation,
2610	                        Title = innerGroup.Title,
2611	                        Parent = newGroupDefinition,
2612	                        Grouping = innerGroup.Grouping,
2613	                        KeyPath = new GroupKeyPath(innerGroup.KeyPath),
2614	                        InnerGroup = innerGroup.InnerGroup
2615	                    };
2616	                }
2617	                result.Add(newGroupDefinition);
2618	            }
2619	            return result;
2620	        }
