2622	        internal async Task UpdateGroupingOrder(Column<T> column, bool added)
2623	        {
2624	            // if added then add to the end if no _groupByOrderState.Value
2625	            if (added)
2626	            {
2627	                var groupedColumns = RenderedColumns.Where(x => x.GroupingState.Value && x != column);
2628	                var newOrder = groupedColumns.Any() ? groupedColumns.Max(x => x._groupByOrderState.Value) + 1 : 0;
2629	                await column._groupByOrderState.SetValueAsync(newOrder);
2630	            }
2631	            // if removed then reset _groupByOrderState.Value
2632	            else
2633	            {
2634	                await column._groupByOrderState.SetValueAsync(default);
2635	            }
2636	            // expand all but last grouped column when changed
2637	            await GroupExpansion();
2638	        }
2639	
2640	        private async Task GroupExpansion()
2641	        {
2642	            var groupedColumns = RenderedColumns.Where(x => x.GroupingState.Value).OrderBy(x => x._groupByOrderState.Value).SkipLast(1);
2643	            foreach (var col in groupedColumns.OrderBy(x => x._groupByOrderState.Value))
2644	            {
2645	                await col._groupExpandedState.SetValueAsync(true);
2646	            }
2647	        }
2648	
2649	        /// <summary>
2650	        /// Toggles the expanded or collapsed state of the specified group by column name and key.
2651	        /// </summary>
2652	        /// <param name="columnName">The name of the grouped column.</param>
2653	        /// <param name="key">The group key identifying the specific group to expand or collapse.</param>
2654	        /// <param name="expanded">Whether the group should be expanded (true) or collapsed (false).</param>
2655	        public void ToggleGroupExpand(string? columnName, object? key, bool expanded)
2656	        {
2657	            var groupKey = new GroupKey(columnName, key);
2658	
2659	            // update the expansion state for _groupExpansionsDict
2660	            // if it has a key we see if it differs from the definition Expanded State and update accordingly
2661	            // if it doesn't we add it if the new state doesn't match the definition
2662	            var col = RenderedColumns.FirstOrDefault(x => x.PropertyName == columnName);
2663	            if (expanded == col?._groupExpandedState.Value)
2664	                _groupExpansionsDict.Remove(groupKey);
2665	            else
2666	                _groupExpansionsDict[groupKey] = expanded;
2667	
2668	            _groupInitialExpanded = false;
2669	            StateHasChanged();
2670	        }
