2687	        /// Collapses all groups async.
2688	        /// </summary>
2689	        /// <remarks>
2690	        /// Applies when <see cref="Groupable"/> is <c>true</c>.
2691	        /// </remarks>
2692	        public async Task CollapseAllGroupsAsync()
2693	        {
2694	            if (_groupDefinition != null && _groupable)
2695	            {
2696	                await ToggleGroupExpandRecursively(false);
2697	            }
2698	        }
