2700	        private async Task ToggleGroupExpandRecursively(bool expanded)
2701	        {
2702	            _groupExpansionsDict.Clear();
2703	            foreach (var column in RenderedColumns)
2704	            {
2705	                if (column.GroupingState.Value)
2706	                {
2707	                    await column._groupExpandedState.SetValueAsync(expanded);
2708	                }
2709	            }
2710	            _groupInitialExpanded = false;
2711	            GroupItems();
2712	        }
