2718	        {
2719	            Debug.Assert(_buttonDisabledFunc is not null);
2720	            var expandedItems = FilteredItems.Where(x => !_buttonDisabledFunc(x) && _openHierarchies.Add(x));
2721	            foreach (var item in expandedItems)
2722	            {
2723	                await HierarchyVisibilityToggled.InvokeAsync(new(item, true));
2724	            }
2725	            await InvokeAsync(StateHasChanged);
