2729	        /// Collapses all Hierarchy columns
2730	        /// </summary>
2731	        public async Task CollapseAllHierarchy()
2732	        {
2733	            Debug.Assert(_buttonDisabledFunc is not null);
2734	            foreach (var openedHierarchy in _openHierarchies.Where(x => !_buttonDisabledFunc(x)).ToList())
2735	            {
2736	                await HierarchyVisibilityToggled.InvokeAsync(new(openedHierarchy, false));
2737	                _openHierarchies.Remove(openedHierarchy);
