2743	        /// Collapses or expands the hierarchy of the specified item.
2744	        /// </summary>
2745	        /// <param name="item">The item whose hierarchy visibility is to be toggled.</param>
2746	        public async Task ToggleHierarchyVisibilityAsync(T item)
2747	        {
2748	            // if ExpandSingleRow is true, clear all open hierarchies, which will immediately add the item that was clicked.
2749	            if (_expandSingleRowState.Value)
2750	            {
