[Test]
        public async Task DataGridSortChangedEvent()
        {
            var comp = Context.Render<DataGridSortChangedEventTest>();
            var dataGrid = comp.FindComponent<MudDataGrid<DataGridSortChangedEventTest.Item>>();

            // Initially the event should not have fired
            comp.Instance.SortChangedFired.Should().Be(false);
            comp.Instance.SortChangedCallCount.Should().Be(0);

            // Call SetSortAsync - should fire SortChanged
            await comp.InvokeAsync(() => dataGrid.Instance.SetSortAsync("Name", SortDirection.Ascending, x => x.Name));

            comp.Instance.SortChangedFired.Should().Be(true);
            comp.Instance.SortChangedCallCount.Should().Be(1);
            comp.Instance.LastSortDefinition.Should().NotBeNull();
            comp.Instance.LastSortDefinition!.SortBy.Should().Be("Name");
            comp.Instance.LastSortDefinition!.Descending.Should().Be(false);

            // Call ExtendSortAsync - should fire SortChanged again
            await comp.InvokeAsync(() => dataGrid.Instance.ExtendSortAsync("Value", SortDirection.Descending, x => x.Value));

            comp.Instance.SortChangedCallCount.Should().Be(2);
            comp.Instance.LastSortDefinition!.SortBy.Should().Be("Value");
            comp.Instance.LastSortDefinition!.Descending.Should().Be(true);

            // Call RemoveSortAsync - should fire SortChanged again
            await comp.InvokeAsync(() => dataGrid.Instance.RemoveSortAsync("Name"));

            comp.Instance.SortChangedCallCount.Should().Be(3);
        }

        #endregion
    }
}

