            await comp.InvokeAsync(() => dataGrid.Instance.SetSelectedItemAsync(true, secondItem));

            await comp.WaitForAssertionAsync(() => dataGrid.Instance.GetState(x => x.SelectedItems).Count.Should().Be(2));

